def evaluate_expression(expr: str) -> str:
    try:
        # Remove whitespace and validate input
        expr = expr.strip()
        if not expr:
            return ""

        # Only allow safe characters for arithmetic expressions
        allowed_chars = set('0123456789+-*/().e ')
        if not all(c in allowed_chars for c in expr):
            return ""

        # Prevent dangerous operations by checking for forbidden patterns
        forbidden = ['__', 'import', 'exec', 'eval', 'open', 'file', 'input', 'raw_input']
        expr_lower = expr.lower()
        if any(pattern in expr_lower for pattern in forbidden):
            return ""

        # Use ast.literal_eval for safe evaluation of simple expressions
        import ast
        import operator

        # Define safe operations
        ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.USub: operator.neg,
            ast.UAdd: operator.pos,
        }

        def safe_eval(node):
            if isinstance(node, ast.Num):
                return node.n
            elif isinstance(node, ast.Constant):
                return node.value
            elif isinstance(node, ast.BinOp):
                left = safe_eval(node.left)
                right = safe_eval(node.right)
                if type(node.op) not in ops:
                    raise ValueError("Unsupported operation")
                return ops[type(node.op)](left, right)
            elif isinstance(node, ast.UnaryOp):
                operand = safe_eval(node.operand)
                if type(node.op) not in ops:
                    raise ValueError("Unsupported operation")
                return ops[type(node.op)](operand)
            else:
                raise ValueError("Unsupported node type")

        # Parse and evaluate
        tree = ast.parse(expr, mode='eval')
        result = safe_eval(tree.body)

        # Handle division by zero and other math errors
        if isinstance(result, (int, float)):
            if result != result:  # NaN check
                return ""
            if result == float('inf') or result == float('-inf'):
                return ""
            return str(result)
        else:
            return ""

    except:
        return ""

def check_email(email: str) -> Tuple[bool, str]:
    pattern = r'^[a-zA-Z0-9]([a-zA-Z0-9._-]*[a-zA-Z0-9])?@[a-zA-Z0-9]([a-zA-Z0-9.-]*[a-zA-Z0-9])?\.[a-zA-Z]{2,}$'

    if not email or len(email) > 254:
        return False, pattern

    if email.count('@') != 1:
        return False, pattern

    local, domain = email.split('@')

    if not local or len(local) > 64 or not domain or len(domain) > 253:
        return False, pattern

    if local.startswith('.') or local.endswith('.') or '..' in local:
        return False, pattern

    if domain.startswith('.') or domain.endswith('.') or '..' in domain:
        return False, pattern

    if domain.startswith('-') or domain.endswith('-'):
        return False, pattern

    is_valid = bool(re.match(pattern, email))
    return is_valid, pattern

